cd /workspace/YatCC && python3 << 'PYEOF'
content = open('task/3/EmitIR.cpp', 'r').read()

# Add getSubType before the Type operator()
getsub = '''
llvm::Type* EmitIR::getSubType(const Type* type)
{
  switch (type->spec) {
    case Type::Spec::kInt: return llvm::Type::getInt32Ty(mCtx);
    case Type::Spec::kChar: return llvm::Type::getInt8Ty(mCtx);
    case Type::Spec::kVoid: return llvm::Type::getVoidTy(mCtx);
    default: ABORT();
  }
}
'''

# Insert getSubType after the type operator() function
content = content.replace('ABORT();\n}\n\n// Expressions', 'ABORT();\n}\n\n' + getsub + '\n// Expressions', 1)

with open('task/3/EmitIR.cpp', 'w') as f:
    f.write(content)
print('Added getSubType')
PYEOF
